script:
# production_dashboard_api (v3 optimized)
# Script Type: API
# API Method: production_dashboard_api
#
# Key upgrades:
# - Safe caps via limit_* args to protect performance on large ranges
# - Avoid per-document get_doc; batch fetch time logs
# - Return distincts for slicers

args = frappe.form_dict

from_date = args.get("from_date")
to_date = args.get("to_date")
company = args.get("company")
production_item = args.get("production_item")
status = args.get("status")
workstation = args.get("workstation")
sales_order = args.get("sales_order")

# Performance caps (frontend sets defaults; you can adjust here)
limit_work_orders = int(args.get("limit_work_orders") or 15000)
limit_job_cards   = int(args.get("limit_job_cards") or 20000)
limit_time_logs   = int(args.get("limit_time_logs") or 50000)

filters = {}
if from_date and to_date:
    filters["planned_start_date"] = ["between", [from_date, to_date]]
if company:
    filters["company"] = company
if production_item:
    filters["production_item"] = production_item
if status:
    filters["status"] = status
if sales_order:
    filters["sales_order"] = sales_order

work_orders = frappe.get_all(
    "Work Order",
    filters=filters,
    fields=[
        "name","company","status","production_item","item_name",
        "qty","produced_qty","planned_start_date","planned_end_date",
        "actual_start_date","actual_end_date","material_transferred_for_manufacturing",
        "sales_order","production_plan"
    ],
    order_by="planned_start_date asc",
    limit_page_length=limit_work_orders,
)

wo_names = [d.get("name") for d in work_orders if d.get("name")]
wo_map = {wo.get('name'): wo for wo in work_orders if wo.get('name')}

# Sales Orders / Production Plans (real documents only, no synthetic buckets)
sales_order_names = list(set([wo.get("sales_order") for wo in work_orders if wo.get("sales_order")]))
production_plan_names = list(set([wo.get("production_plan") for wo in work_orders if wo.get("production_plan")]))

so_filters = {}
if company:
    so_filters["company"] = company
if from_date and to_date:
    so_filters["transaction_date"] = ["between", [from_date, to_date]]
if sales_order:
    so_filters["name"] = sales_order

sales_orders = frappe.get_all(
    "Sales Order",
    filters=so_filters,
    fields=[
        "name", "transaction_date", "customer", "company", "status",
        "delivery_status", "billing_status", "grand_total"
    ],
    order_by="transaction_date asc, name asc",
    limit_page_length=100000,
)

pp_filters = {}
if company:
    pp_filters["company"] = company
if from_date and to_date:
    pp_filters["posting_date"] = ["between", [from_date, to_date]]

production_plans = frappe.get_all(
    "Production Plan",
    filters=pp_filters,
    fields=["name", "posting_date", "company", "status"],
    order_by="posting_date asc, name asc",
    limit_page_length=100000,
)

# Work Order Operations
operations_by_wo = {}
workstation_set = set()

if wo_names:
    op_filters = {"parent": ["in", wo_names], "parenttype": "Work Order"}
    if workstation:
        op_filters["workstation"] = workstation

    op_rows = frappe.get_all(
        "Work Order Operation",
        filters=op_filters,
        fields=["parent","operation","workstation","time_in_mins","completed_qty","status"],
        limit_page_length=100000,
    )
    for row in op_rows:
        parent = row.pop("parent", None)
        if parent:
            operations_by_wo.setdefault(parent, []).append(row)
            if row.get("workstation"):
                workstation_set.add(row["workstation"])

# If workstation filter applied, keep only WOs that have ops in that workstation
if workstation:
    keep = set([k for k,v in operations_by_wo.items() if v])
    work_orders = [wo for wo in work_orders if wo.get("name") in keep]
    wo_names = [d.get("name") for d in work_orders if d.get("name")]
    wo_map = {wo.get('name'): wo for wo in work_orders if wo.get('name')}

# Job Cards
job_cards = []
all_jc_names = set()

if wo_names:
    jc_filters = {"work_order": ["in", wo_names]}
    if company:
        jc_filters["company"] = company

    jc_by_wo = frappe.get_all(
        "Job Card",
        filters=jc_filters,
        fields=[
            "name", "work_order", "production_item", "item_name", "for_quantity",
            "total_completed_qty", "process_loss_qty", "operation", "workstation",
            "workstation_type", "posting_date", "status", "company",
            "expected_start_date", "expected_end_date", "actual_start_date",
            "actual_end_date", "time_required", "total_time_in_mins", "docstatus"
        ],
        order_by="posting_date asc",
        limit_page_length=limit_job_cards,
    )
    for jc in jc_by_wo:
        if jc.get("name"):
            all_jc_names.add(jc.get("name"))
            job_cards.append(jc)

# Also fetch by posting date range to catch job cards even if WO list is capped
if from_date and to_date:
    jc_filters_by_date = {"posting_date": ["between", [from_date, to_date]]}
    if company:
        jc_filters_by_date["company"] = company

    jc_by_date = frappe.get_all(
        "Job Card",
        filters=jc_filters_by_date,
        fields=[
            "name", "work_order", "production_item", "item_name", "for_quantity",
            "total_completed_qty", "process_loss_qty", "operation", "workstation",
            "workstation_type", "posting_date", "status", "company",
            "expected_start_date", "expected_end_date", "actual_start_date",
            "actual_end_date", "time_required", "total_time_in_mins", "docstatus"
        ],
        order_by="posting_date asc",
        limit_page_length=limit_job_cards,
    )
    for jc in jc_by_date:
        jc_name = jc.get("name")
        if jc_name and jc_name not in all_jc_names:
            all_jc_names.add(jc_name)
            job_cards.append(jc)

job_cards = sorted(job_cards, key=lambda x: (x.get("posting_date") or "", x.get("name") or ""))

# Time logs (batch)
employee_time_logs = []
if job_cards:
    jc_names = [jc.get("name") for jc in job_cards if jc.get("name")]

    def chunks_list(lst, n=1000):
        for i in range(0, len(lst), n):
            yield lst[i:i+n]

    time_log_rows = []
    # Try parentfield + fallback
    for batch in chunks_list(jc_names, 1000):
        rows = frappe.get_all(
            "Job Card Time Log",
            filters={
                "parent": ["in", batch],
                "parenttype": "Job Card",
            },
            fields=["parent", "employee", "from_time", "to_time", "time_in_mins", "completed_qty", "operation"],
            limit_page_length=100000,
        )
        time_log_rows.extend(rows)
        if len(time_log_rows) >= limit_time_logs:
            time_log_rows = time_log_rows[:limit_time_logs]
            break

    jc_to_wo = {jc["name"]: jc.get("work_order") for jc in job_cards if jc.get("name")}
    jc_details_map = {jc["name"]: jc for jc in job_cards if jc.get("name")}

    for log in time_log_rows:
        job_card = log.get("parent")
        work_order = jc_to_wo.get(job_card, "") or ""
        employee = log.get("employee") or "(No Employee)"
        from_time = log.get("from_time")
        to_time = log.get("to_time")
        time_in_mins = float(log.get("time_in_mins") or 0)
        completed_qty = float(log.get("completed_qty") or 0)

        # Skip empty/zero logs in Employee tab:
        # no timestamps AND both metrics are zero.
        if (not from_time and not to_time and time_in_mins == 0 and completed_qty == 0):
            continue

        jc_details = jc_details_map.get(job_card, {}) or {}
        wo_details = wo_map.get(work_order, {}) if work_order else {}

        employee_time_logs.append({
            "work_order": work_order,
            "job_card": job_card,
            "employee": employee,
            "from_time": from_time,
            "to_time": to_time,
            "time_in_mins": time_in_mins,
            "completed_qty": completed_qty,
            "operation": log.get("operation") or jc_details.get("operation") or "",
            "production_item": wo_details.get("production_item") or jc_details.get("production_item") or "",
            "item_name": wo_details.get("item_name") or jc_details.get("item_name") or "",
            "company": wo_details.get("company") or jc_details.get("company") or "",
        })

# Distinct values for slicers
company_set = set()
prod_item_set = set()
status_set = set()
employee_set = set()

for wo in work_orders:
    if wo.get("company"): company_set.add(wo["company"])
    if wo.get("production_item"): prod_item_set.add(wo["production_item"])
    if wo.get("status"): status_set.add(wo["status"])

for jc in job_cards:
    if jc.get("company"): company_set.add(jc["company"])
    if jc.get("production_item"): prod_item_set.add(jc["production_item"])
    if jc.get("status"): status_set.add(jc["status"])
    if jc.get("workstation"): workstation_set.add(jc["workstation"])

for log in employee_time_logs:
    emp = log.get("employee")
    if emp and emp != "(No Employee)":
        employee_set.add(emp)

distinct_values = {
    "companies": sorted(company_set),
    "production_items": sorted(prod_item_set),
    "statuses": sorted(status_set),
    "workstations": sorted(workstation_set),
    "employees": sorted(employee_set),
    "sales_orders": sorted(list(set([so.get("name") for so in sales_orders if so.get("name")]))),
    "production_plans": sorted(list(set([pp.get("name") for pp in production_plans if pp.get("name")]))),
}

response_data = {
    "work_orders": work_orders,
    "operations_by_wo": operations_by_wo,
    "job_cards": job_cards,
    "employee_time_logs": employee_time_logs,
    "sales_orders": sales_orders,
    "production_plans": production_plans,
    "distinct_values": distinct_values,
    "debug": {
        "caps": {
            "limit_work_orders": limit_work_orders,
            "limit_job_cards": limit_job_cards,
            "limit_time_logs": limit_time_logs,
        },
        "counts": {
            "work_orders": len(work_orders),
            "job_cards": len(job_cards),
            "employee_time_logs": len(employee_time_logs),
        }
    }
}

frappe.response["message"] = response_data
